def f5396(s, a):
    try:
        r = int(a[0]); c = int(a[1])
    except:
        return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    # Find rfts.AGENT position
    pos_B = None
    for i in range(h):
        for j in range(w):
            if s[i][j] == rfts.AGENT:
                pos_B = (i, j)
                break
        if pos_B: break
    if not pos_B: return False
    # Find agent position
    pos_agent = None
    for i in range(h):
        for j in range(w):
            if s[i][j] == 'agent':
                pos_agent = (i, j)
                break
        if pos_agent: break
    if not pos_agent: return False
    dr = 1 if pos_agent[0] > pos_B[0] else -1 if pos_agent[0] < pos_B[0] else 0
    dc = 1 if pos_agent[1] > pos_B[1] else -1 if pos_agent[1] < pos_B[1] else 0
    if dr == 0 and dc == 0: return False
    count = 0
    steps = max(abs(pos_agent[0] - pos_B[0]), abs(pos_agent[1] - pos_B[1]))
    for k in range(1, steps+1):
        nr = pos_B[0] + dr*k
        nc = pos_B[1] + dc*k
        if 0 <= nr < h and 0 <= nc < w:
            if s[nr][nc] == rfts.AGENT:
                count += 1
    return count >= 1

